		WithPageToken(p.GetPageToken()),
	}

	if po, ok := p.(OffsetPageParameter); ok {
		opts = append(opts, WithOffset(uint64(po.GetOffset())))
	}

	return ListWithOptions[T](t, ListWithQueryParamOptions[T](opts...))
}

